    int nums[N] = {9, 2, 6, 1, 8, 5, 4, 3, 7, 10};
    int i;
    //调用函数进行排序
    int *p = Ins_Sort(N, nums);
    //循环输出排序好的数组，由小到大
    for(i = 0; i < N; i++)
    {
        printf("%d ", p[i]);
    }
    printf("\n");
    for(i = N - 1; i >= 0; i--)
    {
        printf("%d ", p[i]);
    }
    return 0;
}
